class Solution {
public:
    ListNode* deleteDuplicates(ListNode* head) {
        for (ListNode* cur=head; cur && cur->next; )
            if (cur->val == cur->next->val) cur->next = cur->next->next;
            else cur = cur->next;
        return head;
    }
};

